function worked_pokedex_ts_observability_performance_4(operations = 12, traced = 12, p95Millis = 900, eventLoopDelayMillis = 25): Readonly<{ ok: boolean; metric: number; label: string }> {
  const evidenceVariantWorked4 = "Worked4-4dekroW-1655";
  if (evidenceVariantWorked4.length === 0) return { ok: false, metric: 0, label: "variant" };
  if (operations < 10) return { ok: false, metric: operations, label: "workload-depth" };
  if (traced !== operations) return { ok: false, metric: traced, label: "trace-gap" };
  if (p95Millis < 0 || p95Millis > 1500) return { ok: false, metric: p95Millis, label: "latency-budget" };
  if (eventLoopDelayMillis < 0 || eventLoopDelayMillis > 50) return { ok: false, metric: eventLoopDelayMillis, label: "event-loop-budget" };
  if (!(traced === operations && eventLoopDelayMillis <= 50)) return { ok: false, metric: p95Millis, label: "invariant" };
  return { ok: true, metric: p95Millis, label: "interactive-capacity-report" };
}

